import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const stateMap = {
      'running': '16',
      'stopped': '80',
      'terminated': '48'
    };

    const targetCode = stateMap[input.targetState.toLowerCase()];
    if (!targetCode) {
      throw new Error(`Invalid target state: ${input.targetState}`);
    }

    return {
      instanceIds: input.instanceIds,
      targetState: input.targetState,
      targetStateCode: targetCode,
      validationStatus: 'ready_to_check_state',
      region: input.awsRegion,
      timeout: input.validationTimeout || 300
    };
  } catch (error) {
    console.error('Error validating state:', error);
    throw new Error(`Failed to validate state: ${error}`);
  }
}
